const threat = $input.first().json.threat_description || "";
const strideCategories = {
  spoofing: [],
  tampering: [],
  repudiation: [],
  information_disclosure: [],
  denial_of_service: [],
  elevation_of_privilege: []
};

const lowerThreat = threat.toLowerCase();

if (lowerThreat.includes("identity") || lowerThreat.includes("authentication") || lowerThreat.includes("impersonat") || lowerThreat.includes("credential")) {
  strideCategories.spoofing.push(threat);
}

if (lowerThreat.includes("tamper") || lowerThreat.includes("modify") || lowerThreat.includes("alter") || lowerThreat.includes("integrity")) {
  strideCategories.tampering.push(threat);
}

if (lowerThreat.includes("log") || lowerThreat.includes("audit") || lowerThreat.includes("deny") || lowerThreat.includes("repudiat")) {
  strideCategories.repudiation.push(threat);
}

if (lowerThreat.includes("disclosure") || lowerThreat.includes("leak") || lowerThreat.includes("exposure") || lowerThreat.includes("confidential") || lowerThreat.includes("exfiltrat")) {
  strideCategories.information_disclosure.push(threat);
}

if (lowerThreat.includes("dos") || lowerThreat.includes("denial") || lowerThreat.includes("availability") || lowerThreat.includes("flood") || lowerThreat.includes("exhaust")) {
  strideCategories.denial_of_service.push(threat);
}

if (lowerThreat.includes("privilege") || lowerThreat.includes("escalat") || lowerThreat.includes("authorization") || lowerThreat.includes("admin") || lowerThreat.includes("root")) {
  strideCategories.elevation_of_privilege.push(threat);
}

return [{ json: { threat_description: threat, stride_categories: strideCategories, analysis_timestamp: new Date().toISOString() } }];

const input = $input.first().json;

const attackVector = input.attack_vector || "network";
const attackComplexity = input.attack_complexity || "low";
const privilegesRequired = input.privileges_required || "none";
const userInteraction = input.user_interaction || "none";
const scope = input.scope || "unchanged";
const confidentialityImpact = input.confidentiality_impact || "high";
const integrityImpact = input.integrity_impact || "high";
const availabilityImpact = input.availability_impact || "high";

const avScore = attackVector === "network" ? 0.85 : attackVector === "adjacent" ? 0.62 : attackVector === "local" ? 0.55 : 0.2;
const acScore = attackComplexity === "low" ? 0.77 : 0.44;
const prScore = privilegesRequired === "none" ? 0.85 : privilegesRequired === "low" ? 0.62 : 0.27;
const uiScore = userInteraction === "none" ? 0.85 : 0.62;
const scopeMultiplier = scope === "changed" ? 1.08 : 1.0;

const cScore = confidentialityImpact === "high" ? 0.56 : confidentialityImpact === "low" ? 0.22 : 0;
const iScore = integrityImpact === "high" ? 0.56 : integrityImpact === "low" ? 0.22 : 0;
const aScore = availabilityImpact === "high" ? 0.56 : availabilityImpact === "low" ? 0.22 : 0;

const exploitability = 8.22 * avScore * acScore * prScore * uiScore;
const impact = 1 - ((1 - cScore) * (1 - iScore) * (1 - aScore));
const impactSubScore = 6.42 * impact;

let baseScore;
if (impact <= 0) {
  baseScore = 0;
} else {
  if (scope === "unchanged") {
    baseScore = Math.min(exploitability + impactSubScore, 10);
  } else {
    baseScore = Math.min(1.08 * (exploitability + impactSubScore), 10);
  }
}

baseScore = Math.round(baseScore * 10) / 10;

let severity;
if (baseScore === 0) severity = "None";
else if (baseScore < 4.0) severity = "Low";
else if (baseScore < 7.0) severity = "Medium";
else if (baseScore < 9.0) severity = "High";
else severity = "Critical";

return [{ json: { cvss_score: baseScore, severity: severity, exploitability_score: Math.round(exploitability * 10) / 10, impact_score: Math.round(impactSubScore * 10) / 10, parameters: input } }];
